STYLE="""*{box-sizing:border-box}body{margin:0;background:#070711;color:#f7f4ff;font-family:Arial,sans-serif}a{color:inherit;text-decoration:none}.shell{min-height:100vh;display:grid;grid-template-columns:230px 1fr;background:radial-gradient(circle at 55% 0,#251247 0,transparent 35%),#070711}aside{padding:26px 18px;background:#0b0a18;border-right:1px solid #28223b}.brand{font-size:25px;font-weight:800;margin-bottom:30px}.brand b{color:#b451ff}nav a{display:block;padding:12px;border-radius:10px;color:#aaa3ba;margin:4px 0}nav a:hover{background:#20143b;color:white}main{padding:30px;max-width:1400px}.hero{padding:30px;border-radius:20px;background:linear-gradient(135deg,#251049,#751e7c);border:1px solid #56316f;margin-bottom:18px}.hero h1{font-size:38px;margin:0 0 10px}.muted{color:#9a93a8}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(250px,1fr));gap:14px}.card{background:#111020;border:1px solid #29243d;border-radius:15px;padding:18px}.card h2,.card h3{margin-top:0}.metric{font-size:25px;font-weight:800}.pill{display:inline-block;padding:5px 9px;border-radius:999px;background:#261641;color:#cb8eff;font-size:10px;font-weight:800}.pill.ok{background:#153124;color:#75e2a6}.pill.off{background:#351820;color:#ff8b9b}input,select,textarea{width:100%;padding:11px;border:1px solid #3b3152;border-radius:9px;background:#0a0916;color:#fff;margin:6px 0 12px}button,.button{display:inline-block;border:0;border-radius:10px;padding:11px 15px;background:linear-gradient(135deg,#7434ed,#bd45d3);color:white;font-weight:800;cursor:pointer}.button.secondary{background:#1a162c;border:1px solid #3a3150}.project{display:block;transition:.2s}.project:hover{transform:translateY(-2px);border-color:#7645a7}.notice{padding:12px;border:1px solid #3a3050;border-radius:10px;background:#171329;color:#c8bdd4}audio{width:100%}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:9px;border-bottom:1px solid #29243d;font-size:13px}@media(max-width:760px){.shell{display:block}aside{border-right:0;border-bottom:1px solid #28223b}main{padding:18px}}"""
